New behavior: notifications with data.type === 'AT_RISK_REVIEW' open /app?intent=review. If the app is already open, send postMessage instead of navigating.

Replace the existing notificationclick handler with:

  self.addEventListener('notificationclick', function(event) {
    console.log('[SW Push] Notification click received.');
    event.notification.close();

    const data = event.notification.data || {};
    const urlToOpen = data.type === 'AT_RISK_REVIEW' ? '/app?intent=review' : '/app';

    event.waitUntil(
      clients.matchAll({ type: 'window', includeUncontrolled: true })
        .then(function(clientList) {
          for (var i = 0; i < clientList.length; i++) {
            var client = clientList[i];
            if (client.url.includes('/app') && 'focus' in client) {
