  useHotkeys('up',    () => { if (currentItem) onDecision(currentItem.id, { type: 'skipped' }); }, { enabled: !!currentItem });
  useHotkeys('escape', () => { /* parent modal close — pass onClose prop to deck or lift via callback */ }, { enabled: !!currentItem });

